#include<stdio.h>
int main()
{
    int a,b;
    scanf("%d %d" , &a, &b);
    int x,n;
    n=a;
    while(a>=b)
    {
        n=n+(a/b);
        x=a%b;
        a=a/b;
        a=a+x;
    }
    printf("%d" , n);
    return 0;

}

